    }}, 'flowhunt.io/ai-projects'));
  }

  // ===== AMBIENT PARTICLES =====
  if (f >= 30) {
    var partOp = f < 60 ? eo3(p(30, 60)) : 1;
    for (var pi = 0; pi < 14; pi++) {
