      var pSpeed = 0.1 + pSeed * 0.3;
      var pxBase = hash(pi + 800) * W;
      var pPhase = ((f - 30) * pSpeed + pSeed * 200) % 150;
      var pY = H + 10 - pPhase * (H + 30) / 150;
      var pFadeIn = Math.min(pPhase / 12, 1);
